body:
Dedup needs to be expanded to support `strictconnect` ops, handling them the same way it handles regular `connect` ops.  This is not a huge issue because there are no strictconnect ops coming from Chisel and it doesn't normally see any of these ops.
`./bin/firtool -dedup ./test.mlir`
```mlir
firrtl.circuit "Foo"  {
  firrtl.extmodule @Bar(in io: !firrtl.bundle<a: uint<1>>)
  firrtl.extmodule @Baz(in io: !firrtl.bundle<b: uint<1>>)
  firrtl.module @Foo() {
    %bar_io = firrtl.instance bar  @Bar(in io: !firrtl.bundle<a: uint<1>>)
    %baz_io = firrtl.instance baz  @Baz(in io: !firrtl.bundle<b: uint<1>>)
    %w = firrtl.wire  : !firrtl.bundle<b: uint<1>>
    firrtl.strictconnect %w, %baz_io : !firrtl.bundle<b: uint<1>>
  }
}
```
```mlir
./test.mlir:8:5: error: 'firrtl.strictconnect' op requires all operands to have the same type
    firrtl.strictconnect %w, %baz_io : !firrtl.bundle<b: uint<1>>
    ^
./test.mlir:8:5: note: see current operation: "firrtl.strictconnect"(%2, %1) : (!firrtl.bundle<b: uint<1>>, !firrtl.bundle<a: uint<1>>) -> ()
// -----// IR Dump After Dedup Failed //----- //
"firrtl.circuit"() ({
  "firrtl.extmodule"() ({
  }) {annotations = [], parameters = [], portAnnotations = [], portDirections = false, portNames = ["io"], portSyms = [""], portTypes = [!firrtl.bundle<a: uint<1>>], sym_name = "Bar"} : () -> ()
  "firrtl.module"() ({
    %0 = "firrtl.instance"() {annotations = [], lowerToBind = false, moduleName = @Bar, name = "bar", portAnnotations = [[]], portDirections = false, portNames = ["io"]} : () -> !firrtl.bundle<a: uint<1>>
    %1 = "firrtl.instance"() {annotations = [], lowerToBind = false, moduleName = @Bar, name = "baz", portAnnotations = [[]], portDirections = false, portNames = ["io"]} : () -> !firrtl.bundle<a: uint<1>>
    %2 = "firrtl.wire"() {annotations = [], name = "w"} : () -> !firrtl.bundle<b: uint<1>>
    "firrtl.strictconnect"(%2, %1) : (!firrtl.bundle<b: uint<1>>, !firrtl.bundle<a: uint<1>>) -> ()
  }) {annotations = [], parameters = [], portAnnotations = [], portDirections = 0 : i0, portNames = [], portSyms = [], portTypes = [], sym_name = "Foo"} : () -> ()
}) {annotations = [], name = "Foo"} : () -> ()
